var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"공군 기술 연구소 임시 선착장\\n델타 세븐 기함, 엔터프라이즈\\n감찰부대 기습 380초 전","JPN":"空軍技術研究所の臨時船着き場\\nデルタセブンの旗艦、エンタープライズ\\n監察部隊の奇襲まであと380秒","ENG":"Air Force Research Lab Temporary Dock,\\nDelta Seven Flagship, Enterprise\\n380 seconds before the surprise attack by the Inspection Corps.","TWN":"空軍技術研究所 臨時機庫\\n第七三角洲部隊艦船 企業號\\n監察組偷襲前380秒"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 엔터프라이즈의 개장 작업은 어떻게 되어 가고 있지?","JPN":"カイル、エンタープライズの改装作業はどうなっている？","ENG":"Kyle, how are the remodeling on the Enterprise going?","TWN":"凱爾，企業號的改裝作業進行得如何？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기용할 수 있는 인원을 모두 투입한 상태입니다.","JPN":"動員できる人員をすべて投入している状態です。","ENG":"I have deployed all the personnel that I can appoint for it.","TWN":"已投入所有可用人力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시간은 촉박하지만…… 곧 작전 투입은 가능할 겁니다.","JPN":"時間が差し迫っていますが……もうすぐ作戦投入はできるかと。","ENG":"We are short on time... But she should be ready for operations deployment soon.","TWN":"時間是有點急迫……不過應該很快就可以加入作戰。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아, 전력 충원은?","JPN":"よろしい、戦力の補充は？","ENG":"Good. What about the crew?","TWN":"很好，那戰力增員呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님 지시대로 테라사이드 전역에 참전했던 인원들 위주로 소집했습니다.","JPN":"中将の指示どおり、テラサイドの戦域に参戦した者を優先して招集しました。","ENG":"We have been drafting mainly from those who participated in the Terraside battle, as ordered by the Lieutenant General.","TWN":"已經按照中將的指示，針對參加過特拉賽德戰役的人力進行招募。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다만 경찰청에서 파견 나온 분들과 제인 도우라는 용병은 연락이 닿지 않더군요.","JPN":"ただ警察庁から派遣された方々と、ジェーン・ドウという傭兵は連絡がつきませんでした。","ENG":"However, we have not been able to contact those dispatched from the police agency and the mercenary named Jane Doe.","TWN":"不過還沒能和警察局派來的人，與那個叫作珍妮·多伊的傭兵連絡上。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……아쉽지만 어쩔 수 없지.","JPN":"……残念だが仕方ない。","ENG":"...That’s unfortunate, but I guess it can’t be helped.","TWN":"……真可惜，但也沒辦法。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 지금은 한 명이라도 믿을 수 있는 인원이 필요해.","JPN":"しかし今は一人でも信頼できる者が必要だ。","ENG":"Regardless, we need at least one person that we can trust.","TWN":"不過現在需要盡可能召聚信得過的人力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 차라리 본국에 증원 병력을 요청하는 게 낫지 않겠습니까?","JPN":"ならいっそのこと本国へ兵力の増員を要請した方がよろしいのではないでしょうか。","ENG":"In that case, wouldn’t it be better to request reinforcements from HQ?","TWN":"既然如此，那何不乾脆向國家請求增加兵力呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"갑자기 왜 그렇게 보안에 신경을 쓰시는 건지 모르겠습니다.","JPN":"いきなり保安にこだわる理由がわかりません。","ENG":"I don’t understand why we suddenly pay extra attention to security.","TWN":"我不知道為何突然加強戒備。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소집한 인원들은 물론 믿을 수 있는 자들이지만 솔직히 전력으로서 도움이 될 지는……","JPN":"招集した者たちはもちろん信頼できますが、正直戦力として役に立つかは……","ENG":"Of course, we can trust the people that we drafted. But to be honest, I’m not sure how much they'll be helpful in the battlefield...","TWN":"召集起來的這些人當然是信得過沒錯，但老實說，是否能成為戰力……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"더구나 그 룩이라는 소녀는 의심스럽기까지 합니다.","JPN":"それに、あのルークという少女は疑わしいです。","ENG":"Moreover, the girl named Rook is suspicious.","TWN":"而且，那個叫作城堡的女孩，我對她還有些懷疑。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님께서 데려오시긴 했지만 어떤 기록에서도 그녀에 대한 자료를 찾아볼 수 없었습니다.","JPN":"中将が連れてこられたことは知っていますが、どの記録にも彼女に関する資料は見当たりません。","ENG":"Although you brought her here, I couldn’t find any information about her in all of our records.","TWN":"雖然人是中將帶來的，但在紀錄上完全找不到她的相關資料。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……잠재적 아군에게서 지원받은 인원이다.","JPN":"……潜在的な味方が支援してくれた者だ。","ENG":"...She’s support personnel sent by a potential ally.","TWN":"……她是潛在盟軍提供的人力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"일종의 연락책이라고 생각하면 될 거야. 그녀에 대해서는 내가 보증하지.","JPN":"一種の連絡役と考えればいい。彼女については私が保証しよう。","ENG":"Think of her as a contact. I can vouch for her.","TWN":"就把她想成是雙方的橋樑吧，她的部分我可以做擔保。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님께서 그렇게 말씀하신다면 알겠습니다.","JPN":"中将がそうおっしゃるのなら、了解しました。","ENG":"If you say so, then I will take your word for it, Lieutenant General.","TWN":"既然中將這麼說，那我也就不再過問。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그럼 다음으로 제이나 크로펠…… 임시 소령에 대한 처우입니다만……","JPN":"それでは次にジェイナ・クロペル……臨時少佐の処遇についてですが……","ENG":"Next, Jaina Kropel... Regarding the treatment of the acting major─","TWN":"接下來是婕娜·克洛佩爾……雖然她現在暫時是少校……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"방금 무슨 소리지? 폭발음 같았는데.","JPN":"今の音はなんだ？　爆発音のようだったが。","ENG":"What was that? It sounded like an explosion.","TWN":"剛剛是什麼聲音？好像是爆炸聲？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 기습이야! 이상한 녀석들이 기지에 쳐들어왔어!","JPN":"おばさん！　不意打ちだ！　変な奴らが基地を攻撃してる！","ENG":"Maria! It’s a surprise attack! Some weird guys are invading the base!","TWN":"大嬸！有偷襲！有奇怪的傢伙衝進基地！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고요? 여긴 군사기밀 시설입니다. 감히 누가 공격을 한단 말입니까?","JPN":"なんですって？　ここは軍事機密施設ですよ。いったい誰が攻撃するというのですか？","ENG":"What? This is a secret military base. Who would dare to attack here?","TWN":"你說什麼？這裡可是軍事秘密基地，竟然有人敢攻擊這裡？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당장 인근 주둔군에게 지원 요청을 부탁합니다!","JPN":"今すぐ近くの駐屯軍に支援要請をお願いします！","ENG":"Request immediate assistance from all nearby occupation forces!","TWN":"立刻向附近的駐紮軍請求支援！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당연히 했지! 그런데 전부 무시 당했어!","JPN":"もちろんしたよ！　でも全部無視された！","ENG":"Of course I already did that! But everybody ignored my call!","TWN":"早就通知啦！但沒人理我！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고요? 어째서…… 설마 그쪽도 당한 겁니까?","JPN":"なんですって？　どうして……まさかあそこもやられたのですか？","ENG":"What? How come... Could all of them have been wiped out?","TWN":"什麼？怎麼會……難道他們也遭到突襲嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그게 아니라…… 쳐들어 온 놈들이 그 주둔군인 것 같아.","JPN":"そうじゃなくて……攻めてきた奴らがその駐屯軍みたいなんだ。","ENG":"That’s not it... I think that the occupation forces are the invaders.","TWN":"不是……那些衝進來的傢伙好像就是駐紮軍。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네? 그게 무슨 말도 안되는 소리입니까?","JPN":"はい？　何を訳のわからないことを言ってるんですか？","ENG":"Excuse me? What kind of nonsense is that?","TWN":"什麼？這是什麼荒謬的發言？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"중장님, 노파심이긴 하지만 한 가지 충고를 드리죠.","JPN":"中将、余計なお世話ですが、一つ忠告しておきましょう。","ENG":"Lieutenant General, I am giving you this advice out of concern.","TWN":"中將，就當我雞婆，我要給你個忠告。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……충고?","JPN":"……忠告？","ENG":"...Advice?","TWN":"……忠告？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"신중히, 믿을 수 있는 자들을 모으십시오.","JPN":"慎重に、信頼できる者を集めてください。","ENG":"Use discretion and recruit only those who you trust.","TWN":"請你一定要慎選信得過的人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희는 많은 준비를 해 왔지만, 그 만큼 적들도 오랫동안 준비를 해 왔습니다.","JPN":"私たちは様々な準備をしてきましたが、それだけ敵も長い間準備してきました。","ENG":"We may have made many preparations, but our enemies have also been preparing for a long time.","TWN":"雖然我們一直有在做準備，但敵人這段時間也沒鬆懈。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그들 중 일부는 어쩌면 우리들 사이에 숨어 있을 수도 있습니다.","JPN":"彼らのうち一部はもしかすると私たちの中に潜んでいるかもしれません。","ENG":"Some may already be hiding within our ranks.","TWN":"很有可能，他們有部分的人已經混到我們當中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"특히 당신은 우리 같은 용병이 아니니, 싸우지 않고도 무력화시킬 방법은 많겠죠.","JPN":"特にあなたは私たちのような傭兵ではないので、戦わずに無力化させる方法はたくさんあるでしょう。","ENG":"Especially since you're not a mercenary like us, there are many ways to neutralize you without a fight.","TWN":"尤其你們不像我們是傭兵，就算不開打，也有很多方法可以擊潰你們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상대는 분명 우리가 가장 약한 부분을 치고 들어올 겁니다.","JPN":"相手はきっと私たちの一番弱いところにつけ込むはずです。","ENG":"The enemy will surely aim for our weak spots.","TWN":"對方一定會針對我們最弱的部分進攻。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……충고 고맙군.","JPN":"……忠告に感謝する。","ENG":"...Thanks for the advice.","TWN":"……謝謝你的忠告。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 군인에겐 군인의 방식이 있네. 그걸 저버릴 수는 없어.","JPN":"だが軍人には軍人のやり方がある。それをないがしろにすることはできん。","ENG":"However, as soldiers, we have a code to follow. We cannot abandon that.","TWN":"不過軍人有軍人的做事方法，那是我們無法捨棄的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그게 바로 우리를 강하게 만드는 힘이니까.","JPN":"それこそが我らを強くする力なのだからな。","ENG":"After all, that’s what makes us strong.","TWN":"因為那就是使我們變強大的力量。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연…… 이런 방식으로 흔든단 말이지, 아주 재미있어.","JPN":"なるほど……こういう風に揺さぶるか。とても面白いな。","ENG":"So... This is how you’re gonna shake things up, is it? Very interesting.","TWN":"果然……要用這種方法來動搖軍心是吧，非常有意思。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"덕분에 구 관리국의 초인들에게 인간이 준비해 온 힘을 보여줄 수 있겠군.","JPN":"おかげで旧管理局の超人たちに人間が準備してきた力を見せられる。","ENG":"Thanks to you, we get to show the superhumans of the Old Administration the power that humans have been preparing all this time.","TWN":"很好，那我就可以趁機讓舊管理局的超人見識一下人類準備的力量。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님……? 무슨 말씀을 하시는 겁니까?","JPN":"中将……？　どういうことですか？","ENG":"Lieutenant General...? What are you talking about?","TWN":"中將……？您在說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 아무것도 아니야.","JPN":"いいや、何でもない。","ENG":"Nothing. Ignore what I just said.","TWN":"沒事，沒什麼。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"최대한 교전을 피하고 엔터프라이즈가 움직일 수 있을 때까지 방어에 집중하도록.","JPN":"なるべく交戦を避け、エンタープライズが動けるようになるまで防御に集中しろ。","ENG":"Avoid engagement as much as possible and focus on defense until the Enterprise can move.","TWN":"盡可能避免開戰，在企業號可以移動前，先加強防守。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"적들의 정체와 이후의 대응에 대해서는 다시 지시하겠네.","JPN":"敵の正体と以後の対応については再び指示を出そう。","ENG":"I’ll provide further orders regarding the identity of the enemy and our response measures.","TWN":"關於敵人的身分和之後的策略，我會再跟你說。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 즉시 출동하겠습니다!","JPN":"かしこまりました。ただちに出動いたします！","ENG":"Understood. Deploying immediately!","TWN":"是，中將，我們立刻出動！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};